# *args və **kwargs nümunəsi
def sum_numbers(*args):
    total = 0
    for num in args:
        total += num
    return total

def print_info(**kwargs):
    for key, value in kwargs.items():
        print(f'{key}: {value}')

result = sum_numbers(1, 2, 3, 4)
print(f'Cəmi: {result}')
print_info(name='Ali', age=20)

