# Səhv idarəetməsi
def divide(a, b):
    try:
        result = a / b
        return result
    except ZeroDivisionError:
        return 'Xəta: Sıfıra bölmək olmaz!'
    except TypeError:
        return 'Xəta: Arqumentlər rəqəm olmalıdır!'

print(divide(10, 2))
print(divide(10, 0))
print(divide(10, '2'))

# Məlumat emalı nümunəsi
def filter_positives(numbers):
    positives = []
    for num in numbers:
        if num > 0:
            positives.append(num)
    return positives

numbers = [-2, 1, -1, 3, 5]
result = filter_positives(numbers)
print(f'Müsbət rəqəmlər: {result}')

